import React from 'react';
import { Carousel } from 'antd';
const contentStyle = {
  height: '160px',
  color: '#fff',
  lineHeight: '160px',
  textAlign: 'center',
  background: '#364d79',
};
const HomeCarousel = () => (
  <Carousel autoplay>
    <div className=''>
    <h3 style={contentStyle}>
      <img src="/carousel1.avif" alt="Carousel 1" className='w-screen object-cover' />
    </h3>
    </div>
    <div>
      <h3 style={contentStyle}>2</h3>
    </div>
    <div>
      <h3 style={contentStyle}>3</h3>
    </div>
    <div>
      <h3 style={contentStyle}>4</h3>
    </div>
  </Carousel>

);
export default HomeCarousel;
